function ellipsisMiddle(text2, maxLength = 60) {
  if (text2.length <= maxLength) {
    return text2;
  }
  const ellipsis = "...";
  const charsToShow = maxLength - ellipsis.length;
  const start = Math.ceil(charsToShow / 2);
  const end = text2.length - Math.floor(charsToShow / 2);
  return text2.slice(0, start) + ellipsis + text2.slice(end);
}
